#include <iostream>
#include <vector>
#include <string>
#include <limits> 

// Function declaration (actual implementation will be in the specific file)
int countDigits(int num);

struct TestCase {
    int input;
    int expected;
    std::string description;
};

int main() {
    std::vector<TestCase> testCases = {
        {12345, 5, "Positive number"},
        {0, 1, "Zero"},
        {-9876, 4, "Negative number"},
        {7, 1, "Single digit positive"},
        {-1, 1, "Single digit negative"},
        {std::numeric_limits<int>::max(), 10, "INT_MAX"},
        {std::numeric_limits<int>::min(), 10, "INT_MIN"}
    };

    for (const auto& tc : testCases) {
        int result = countDigits(tc.input);
        std::cout << "Test Case: " << tc.description << " (Input: " << tc.input << ")" << std::endl;
        std::cout << "Expected: " << tc.expected << ", Got: " << result;
        if (result == tc.expected) {
            std::cout << " [PASSED]" << std::endl;
        } else {
            std::cout << " [FAILED]" << std::endl;
        }
        std::cout << "---------------------------------" << std::endl;
    }

    return 0;
}
